#include <stdio.h>
#include <stdbool.h>
#include <math.h>

bool checkSquareSum(long long int c) {
    long long left = 0;
    long long right = (long long) sqrt(c);

    while (left <= right) {
        long long sum = left * left + right * right;
        if (sum == c) {
            return true;
        } else if (sum < c) {
            left++;
        } else {
            right--;
        }
    }

    return false;
}

int main() {
    long long int c;
    scanf("%lld", &c);

    if (checkSquareSum(c)) {
        printf("true\n");
    } else {
        printf("false\n");
    }

    return 0;
}

